      expect(playlist.id, 'p1');
      expect(playlist.name, 'My Playlist');
      expect(playlist.imageUrl, 'https://img.example.com/pl.jpg');
      expect(playlist.songs, songs);
    });

    test('empty songs list is valid', () {
      final playlist = Playlist(
        id: 'p2',
        name: 'Empty',
        imageUrl: '',
        songs: [],
      );
      expect(playlist.songs, isEmpty);
    });
  });

  group('Album', () {
    test('stores all fields correctly', () {
      final album = Album(
        id: 'al1',
        name: 'Greatest Hits',
        artist: 'Some Artist',
        imageUrl: 'https://img.example.com/album.jpg',
        songs: [],
      );

      expect(album.id, 'al1');
      expect(album.name, 'Greatest Hits');
      expect(album.artist, 'Some Artist');
      expect(album.imageUrl, 'https://img.example.com/album.jpg');
      expect(album.songs, isEmpty);
    });
  });
}

