import 'package:mockito/annotations.dart';
import 'package:mockito/mockito.dart';
import 'package:youtube_explode_dart/youtube_explode_dart.dart';
import 'package:http/http.dart' as http;

import 'package:music_app/services/youtube_service.dart';
import 'package:music_app/models/music_models.dart';

import 'youtube_service_test.mocks.dart';

// Classes to mock from youtube_explode_dart
@GenerateMocks([
  YoutubeExplode,
  SearchClient,
  VideoClient,
  PlaylistClient,
  StreamClient,
  http.Client,
])
void main() {
  late MockYoutubeExplode mockYt;
  late MockSearchClient mockSearch;
  late MockVideoClient mockVideoClient;
  late MockPlaylistClient mockPlaylistClient;
  late MockStreamClient mockStreamClient;
  late MockClient mockHttpClient;
  late YouTubeService service;

  // Helper to build a fake Video
  Video _fakeVideo({
    String id = 'vid1',
    String title = 'Test Song',
    String author = 'Test Artist',
    Duration? duration,
  }) {
    final mockVideo = MockVideo();
    when(mockVideo.id).thenReturn(VideoId(id));
    when(mockVideo.title).thenReturn(title);
    when(mockVideo.author).thenReturn(author);
    when(mockVideo.duration).thenReturn(duration ?? const Duration(seconds: 200));
    final mockThumbnails = MockThumbnailSet();
    when(mockThumbnails.highResUrl).thenReturn('https://img.example.com/$id.jpg');
    when(mockVideo.thumbnails).thenReturn(mockThumbnails);
    return mockVideo;
  }

  setUp(() {
    mockYt = MockYoutubeExplode();
    mockSearch = MockSearchClient();
    mockVideoClient = MockVideoClient();
    mockPlaylistClient = MockPlaylistClient();
    mockStreamClient = MockStreamClient();
    mockHttpClient = MockClient();

    when(mockYt.search).thenReturn(mockSearch);
    when(mockYt.videos).thenReturn(mockVideoClient);
    when(mockYt.playlists).thenReturn(mockPlaylistClient);
    when(mockVideoClient.streamsClient).thenReturn(mockStreamClient);

    service = YouTubeService(yt: mockYt, httpClient: mockHttpClient);
  });

  group('YouTubeService.searchSongs', () {
    test('returns up to 5 songs mapped from search results', () async {
      final videos = List.generate(7, (i) => _fakeVideo(id: 'v$i', title: 'Song $i'));
      when(mockSearch.search(any)).thenAnswer((_) async => videos);

      final result = await service.searchSongs('test query');

      expect(result.length, 5);
      expect(result.first.title, 'Song 0');
      expect(result.first.audioUrl, ''); // not fetched yet
    });

