import 'package:mockito/mockito.dart';
import 'package:http/http.dart' as http;
import 'package:youtube_explode_dart/youtube_explode_dart.dart';

import 'package:music_app/services/youtube_service.dart';

import 'youtube_service_test.mocks.dart';

@GenerateMocks([YoutubeGateway, http.Client])
void main() {
  late MockYoutubeGateway mockGateway;
  late MockClient mockHttpClient;
  late YouTubeService service;

  Video _fakeVideo({
    String id = 'v1',
    String title = 'Test Song',
    String author = 'Test Artist',
    Duration? duration,
    String thumbUrl = 'https://img.example.com/thumb.jpg',
  }) {
    // Video is a freezed abstract class — use its factory constructor
    return Video(
      VideoId(id),
      title,
      author,
      ChannelId('UC_test'),
      DateTime(2024),
      null,
      null,
      ThumbnailSet(id),
      duration ?? const Duration(seconds: 200),
      Engagement(1000, null, null),
      false,
      null,
    );
  }

  setUp(() {
    mockGateway = MockYoutubeGateway();
