void nextSong() {
  if (!_isInitialized) return;
  if (_queue.isNotEmpty && _currentIndex < _queue.length - 1) {
    _currentIndex++;
    _currentSong = _queue[_currentIndex];
    _audioHandler.skipToNext();
    notifyListeners();
  }
}

void previousSong() {
  if (!_isInitialized) return;
  if (_queue.isNotEmpty && _currentIndex > 0) {
    _currentIndex--;
    _currentSong = _queue[_currentIndex];
    _audioHandler.skipToPrevious();
    notifyListeners();
  }
}

